async function placeOrder(cart: Cart, buyerOrgId: string, idemKey: string): Promise<Order> {
  // Idempotency: a retried submit returns the original Order instead of creating a new one.
  const existing = await idempotency.lookup(idemKey);
  if (existing) return existing.order;

  // 1. Split the multi-supplier cart into one FulfillmentGroup per supplier.
  const groups = groupBySupplier(cart.items); // Map<supplierId, CartItem[]>

  // 2. Snapshot pricing per line: ContractPrice (buyer-specific) > PriceList. Integer KRW.
  const priced = await pricing.snapshot(buyerOrgId, groups); // immutable unit + line totals

  // 3. Synchronous credit-limit check against the buyer Organization (blocking by design).
  const orderTotal = sumLineTotals(priced); // bigint won, no minor units
  await credit.assertWithinLimit(buyerOrgId, orderTotal); // throws CreditDeclined

  // 4. Two-phase inventory: soft-hold in Redis (TTL). Lock SKUs in sku_id order (deadlock avoidance).
  const holds = await inventory.softHold(
    priced.lines.sort((a, b) => (a.skuId < b.skuId ? -1 : 1))
  ); // throws InsufficientStock -> prior holds released

  // 5. Tax/fee on snapshotted totals; the single documented rounding rule is applied only here.
  const fees = pricing.calcFees(priced);

  // 6. Persist Order + groups + OutboxEvent atomically. Commit is the point of no return.
  return db.transaction(async (tx) => {
    const order = await tx.orders.insert({
      buyerOrgId,
      status: 'PLACED',
      total: orderTotal,
      fees,
    });

    for (const [supplierId, lines] of priced.bySupplier) {
      const fg = await tx.fulfillmentGroups.insert({
        orderId: order.id,
        supplierId,
        status: 'AWAITING_SUPPLIER', // the only entry state
      });
      await tx.orderLines.insertMany(fg.id, lines); // snapshotted price is immutable from here
    }

    // Transactional outbox: published by a worker AFTER commit. No DB-then-SQS dual write.
    await tx.outbox.insert({
      eventType: 'OrderPlaced',
      aggregateId: order.id,
      payload: { orderId: order.id, buyerOrgId, holdIds: holds.ids },
    });

    await tx.idempotency.record(idemKey, order.id);
    return order;
  });
}

async function acceptGroup(groupId: string, supplierUserId: string): Promise<void> {
  await db.transaction(async (tx) => {
    // Guarded transition: only AWAITING_SUPPLIER -> ACCEPTED is permitted by the transitions table.
    const fg = await tx.fulfillmentGroups.selectForUpdate(groupId);
    assertTransition(fg.status, 'ACCEPTED'); // throws on illegal (from,to)

    // Re-price + re-validate against current Postgres data to catch stale prices since placement.
    await pricing.revalidateSnapshot(fg); // throws StalePrice -> surface to supplier, no confirm

    for (const line of await tx.orderLines.byGroup(groupId)) {
      // Hard-confirm: lock the inventory row, decrement under version + CHECK (available >= 0).
      const item = await tx.inventoryItems.selectForUpdate(line.skuId, line.location);
      if (item.available < line.qty) throw new InsufficientStock(line.skuId);
      await tx.inventoryItems.decrement({
        skuId: line.skuId,
        location: line.location,
        qty: line.qty,
        expectedVersion: item.version, // optimistic version guard
      }); // CHECK (available >= 0) is the last line of defense against oversell

      // Promote the Redis soft-hold into a durable Postgres StockReservation (CONFIRMED).
      await tx.stockReservations.confirm(line.reservationId);
    }

    await tx.fulfillmentGroups.transition(groupId, 'ACCEPTED');
    await tx.outbox.insert({
      eventType: 'GroupAccepted',
      aggregateId: groupId,
      payload: { groupId },
    });
  }); // bounded retry wraps this call on deadlock (SQLSTATE 40P01)
}
